  ('heelevel3-6f0ba476-moex-00684', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-f6c431ec', 'sub-heelevel3-6f0ba476-04', NULL, 'single_choice', '假設每個人效用函數相同且僅受所得影響，效用高低也可以比較。在所得邊際效用遞減的前提下， 所得稅制應具有何種特性，才能滿足相等邊際犧牲（equalmarginalsacrifice）公平？', '["累退稅率結構", "比例稅率結構", "累進稅率結構", "任何稅率結構皆可達成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:33+00:00", "source_pdf_sha1": "13fea319c49b", "answer_pdf_sha1": "816865504eb7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
