  ('heelevel3-6f0ba476-moex-00686', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-f6c431ec', 'sub-heelevel3-6f0ba476-04', NULL, 'single_choice', '若所得稅的稅收函數為T=(Y－F)×t（式中T為稅收，Y為所得，F為免稅額且F>0，t為稅率）， 則該稅制之平均稅率（At）及邊際稅率（Mt）：', '["At是固定的，Mt是固定的", "At是固定的，Mt是遞增的", "At是遞增的，Mt是固定的", "At是遞增的，Mt是遞增的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:33+00:00", "source_pdf_sha1": "13fea319c49b", "answer_pdf_sha1": "816865504eb7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
